  ('pukao-e3452428-moex-00565', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '因境內人口日漸流失，由鄉鎮自行設置廢棄物處理設施不符合經濟效益，某縣內數個鄉鎮決定共 同設置、使用相關車輛、人員、設備。關於本件跨區域合作事項之成立要件與後續效果，下列何 者不符地方制度法規定？', '["參與合作之鄉鎮得訂定協議或行政契約作為執行合作事項之依據", "設施興建、設備購置與人員聘任所需預算仍須經各鄉鎮民代表會同意", "本件合作事項經共同上級業務主管機關核准後生效", "共同上級業務主管機關應優先補助本件合作事項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00566', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '下列何者為具公法人地位之地方自治團體？', '["臺中市霧峰區", "桃園市觀音區", "臺南市大內區", "高雄市茂林區"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00567', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '關於直轄市之敘述，下列何者錯誤？', '["直轄市設置標準之一，為人口聚居達125萬人以上", "直轄市名稱之變更，由直轄市政府提請直轄市議會通過，報行政院備查", "直轄市長因案去職，由行政院派員代理，所遺任期不足2年者，不再補選", "直轄市長死亡時，副市長隨同離職"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00568', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '依司法院大法官解釋意旨，關於地方自治團體財政自主權之敘述，下列何者正確？', '["基於地方政府之協力義務，中央得將與地方政府執掌全然無關之事務之經費支出，規定由地方 政府負擔", "地方自治團體所應與中央分擔之經費支出，如符合事物本質者，尚不能認為已侵害地方自治團 體財政自主權之核心領域", "社會福利事項，係中央政府實現人民享有人性尊嚴之生活所應盡之照顧義務，地方自治團體並 無協力之義務", "法律之實施須由地方負擔經費者，於制定過程中應先行徵得地方政府之同意，以利於維繫地方 自治團體自我負責之機制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00569', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '下列何者非屬地方性公民投票適用之事項？', '["地方自治機關之預算案", "地方自治條例之複決", "地方自治條例立法原則之創制", "地方自治事項重大政策之複決"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00570', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '甲為縣政府所屬藝文展演中心無給職顧問，當選縣議員後仍繼續擔任該職務，甲宣誓就職後，對 該顧問職務有無影響？又甲如於就職後始擔任該顧問職務，結果有無不同？', '["由於顧問職屬於無給職且具公益性，無論甲就任議員前或就職後擔任該職，均不受議員身分影響", "甲就職後，應向藝文展演中心表示辭職，如甲未為之，始由內政部通知該藝文展演中心予以解 聘；如就職後擔任，亦應由甲向藝文展演中心表示辭職，如甲未為之，始由內政部為前述通知", "甲就職時，視同辭去該顧問職務，並由內政部通知該藝文展演中心予以解聘；如就職後擔任， 亦由內政部為前述通知", "甲就職時，視同辭去該顧問職務，並由內政部通知該藝文展演中心予以解聘；如就職後擔任， 則不受議員身分影響，得繼續擔任該職務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00571', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '地方制度法對於下列何種地方自治團體之設置，訂有聚居人口之標準？', '["縣轄市", "鄉", "鎮", "直轄市之山地原住民區"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00572', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '關於自治法規之敘述，下列何者錯誤？', '["由地方立法機關通過，並經各該行政機關公布者，稱為自治條例", "地方行政機關就其自治事項，得基於法律或自治條例的授權，訂定自治規則", "地方行政機關將其公權力委託私人行使時，該私人得訂定委辦規則", "地方立法機關訂定之自律規則，原則上應由其自行發布，並報各該上級政府備查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00573', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '直轄市法規、縣（市）規章就違反自治事項有關規定之行為，得訂定罰則，其處罰種類不包含下 列何者？', '["新臺幣10萬元以下之罰鍰", "按次連續處以罰鍰", "至指定處所接受講習、輔導教育", "勒令停工、停止營業"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00574', 'pukao-e3452428', 'pukao-e3452428-moex-110-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '颱風過後，由某山地鄉管理之道路路基流失，嚴重影響交通安全。縣政府認為情況急迫，乃決定 代行處理，修復該道路，並向該鄉公所請求代行處理之費用。如鄉公所認為，縣政府應先定期限 由其自行修復，而擬爭執逕行代行處理之行為違法時，應如何為之？', '["向內政部提出申訴", "由省政府進行協調", "向司法院聲請解釋", "依行政救濟程序辦理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:23+00:00", "source_pdf_sha1": "1fdfeb582cf6", "answer_pdf_sha1": "fbc560425d02", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "402", "s": "0509", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL)
